   1→import { useEffect, useMemo, useRef, useState } from "react";
   2→import Konva from "konva";
   3→import { Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
   4→import { BarLoader } from "react-spinners";
   5→import { useQueryClient } from "@tanstack/react-query";
   6→import { saveJournal, saveJournalImage } from "../../../../API/Api";
   7→import { useAuth } from "../../../Context/useAuth";
   8→import { parseCanvasDoc } from "../../../utils/canvasDoc";
   9→import PieMenu from "./PieMenu";
  10→import styles from "./CanvasEditor.module.css";
  11→import "./canvas.css";
  12→
  13→const FONT_BRUSHES = {
  14→    serif: {label: "Typewriter", fontFamily: "\"Courier New\", \"Lucida Console\", monospace", fontStyle: "normal", preview: "Ink Tape"},
  15→    handwritten: {label: "Brush Script", fontFamily: "\"Comic Sans MS\", \"Bradley Hand\", cursive", fontStyle: "normal", preview: "Wild Brush"},
  16→    bold: {label: "Street Bold", fontFamily: "\"Trebuchet MS\", \"Gill Sans\", sans-serif", fontStyle: "bold", preview: "Tagline"},
  17→    serifDisplay: {label: "Poster Serif", fontFamily: "Georgia, \"Times New Roman\", serif", fontStyle: "normal", preview: "Headline"}
  18→};
  19→
  20→const FONT_STYLE_MAP = {
  21→    serif: "serif",
  22→    handwritten: "handwritten",
  23→    bold: "bold",
  24→    mono: "serif",
  25→    serifDisplay: "serifDisplay"
  26→};
  27→
  28→const GRID_SIZE = 24;
  29→const CANVAS_MAX_WIDTH = 560;
  30→const MOBILE_BREAKPOINT = 820;
  31→const MIN_VIEWPORT_SCALE = 0.85;
  32→const MAX_VIEWPORT_SCALE = 3;
  33→const OBJECT_LIFT_MULTIPLIER = 1.03;
  34→
  35→const COLOR_PALETTES = [
  36→    {label: "Pastels", colors: ["#f8c8dc", "#f9e2af", "#b7e4c7", "#bde0fe", "#d7c3ff"]},
  37→    {label: "Earth", colors: ["#8c5e3c", "#b7794b", "#5a6d4d", "#4d6f75", "#2f3e46"]},
  38→    {label: "Neon", colors: ["#ff2d55", "#ff7a00", "#f7ff00", "#00e5ff", "#8a2be2"]}
  39→];
  40→
  41→const DEFAULT_DOODLE_COLOR = COLOR_PALETTES[2].colors[0];
  42→
  43→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  44→const createId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  45→const randomPlacement = () => ({
  46→    rotation: (Math.random() - 0.5) * 10,
  47→    xOffset: (Math.random() - 0.5) * 0.06,
  48→    yOffset: (Math.random() - 0.5) * 0.06
  49→});
  50→
  51→const sanitizeNormalizedPoints = (rawPoints) => {
  52→    if(!Array.isArray(rawPoints)){
  53→        return [];
  54→    }
  55→
  56→    const numericPoints = rawPoints
  57→        .map((point) => Number(point))
  58→        .filter((point) => !Number.isNaN(point))
  59→        .map((point) => clamp(point, 0, 1));
  60→
  61→    if(numericPoints.length < 2){
  62→        return [];
  63→    }
  64→
  65→    return numericPoints.length % 2 === 0 ? numericPoints : numericPoints.slice(0, -1);
  66→};
  67→
  68→const getStageHeight = (width, aspectRatio) => (aspectRatio === "4:5" ? Math.round(width * 1.25) : width);
  69→
  70→const getLegacyFontStyle = (fontStyle) => {
  71→    if(fontStyle === "mono"){
  72→        return "serif";
  73→    }
  74→    return FONT_STYLE_MAP[fontStyle] ? fontStyle : "serif";
  75→};
  76→
  77→const getSnippetMetrics = (snippet, stageWidth) => {
  78→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
  79→    const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
  80→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
  81→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
  82→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
  83→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
  84→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
  85→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
  86→    return {width: estimatedWidth, height, fontSize};
  87→};
  88→
  89→const constrainViewport = (candidate, stageWidth, stageHeight) => {
  90→    const scale = clamp(candidate?.scale || 1, MIN_VIEWPORT_SCALE, MAX_VIEWPORT_SCALE);
  91→    const scaledWidth = stageWidth * scale;
  92→    const scaledHeight = stageHeight * scale;
  93→    let minX = Math.min(0, stageWidth - scaledWidth);
  94→    let maxX = 0;
  95→    let minY = Math.min(0, stageHeight - scaledHeight);
  96→    let maxY = 0;
  97→
  98→    if(scaledWidth <= stageWidth){
  99→        const centeredX = (stageWidth - scaledWidth) / 2;
 100→        minX = centeredX;
 101→        maxX = centeredX;
 102→    }
 103→    if(scaledHeight <= stageHeight){
 104→        const centeredY = (stageHeight - scaledHeight) / 2;
 105→        minY = centeredY;
 106→        maxY = centeredY;
 107→    }
 108→
 109→    return {
 110→        scale,
 111→        x: clamp(candidate?.x || 0, minX, maxX),
 112→        y: clamp(candidate?.y || 0, minY, maxY)
 113→    };
 114→};
 115→
 116→const getTouchGeometry = (nativeEvent, stage) => {
 117→    const touches = nativeEvent?.touches;
 118→    if(!stage || !touches || touches.length < 2){
 119→        return null;
 120→    }
 121→
 122→    const bounds = stage.container()?.getBoundingClientRect();
 123→    if(!bounds){
 124→        return null;
 125→    }
 126→
 127→    const first = touches[0];
 128→    const second = touches[1];
 129→    const firstPoint = {x: first.clientX - bounds.left, y: first.clientY - bounds.top};
 130→    const secondPoint = {x: second.clientX - bounds.left, y: second.clientY - bounds.top};
 131→
 132→    return {
 133→        center: {x: (firstPoint.x + secondPoint.x) / 2, y: (firstPoint.y + secondPoint.y) / 2},
 134→        distance: Math.hypot(secondPoint.x - firstPoint.x, secondPoint.y - firstPoint.y)
 135→    };
 136→};
 137→
 138→const useLoadedImage = (src) => {
 139→    const [image, setImage] = useState(null);
 140→
 141→    useEffect(() => {
 142→        if(!src){
 143→            setImage(null);
 144→            return;
 145→        }
 146→
 147→        const img = new window.Image();
 148→        img.crossOrigin = "anonymous";
 149→        img.onload = () => setImage(img);
 150→        img.onerror = () => setImage(null);
 151→        img.src = src;
 152→
 153→        return () => {
 154→            img.onload = null;
 155→            img.onerror = null;
 156→        };
 157→    }, [src]);
 158→
 159→    return image;
 160→};
 161→
 162→const CanvasImageNode = ({
 163→    canvasImage,
 164→    stageWidth,
 165→    stageHeight,
 166→    isSelected,
 167→    isDragging,
 168→    onSelect,
 169→    onDragStart,
 170→    onDragEnd,
 171→    canInteract,
 172→    preventTouchDefault,
 173→    isBeingRemoved
 174→}) => {
 175→    const loadedImage = useLoadedImage(canvasImage?.src);
 176→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 177→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 178→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 179→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 180→    const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
 181→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
 182→
 183→    return (
 184→        <>
 185→            <KonvaImage
 186→                name={canvasImage?.id}
 187→                x={x}
 188→                y={y}
 189→                width={objectWidth}
 190→                height={objectHeight}
 191→                image={loadedImage}
 192→                draggable={canInteract && !isBeingRemoved}
 193→                rotation={canvasImage?.rotation || 0}
 194→                scaleX={baseScaleX * liftMultiplier}
 195→                scaleY={liftMultiplier}
 196→                shadowColor="rgba(0,0,0,0.3)"
 197→                shadowBlur={isSelected || isDragging ? 16 : 8}
 198→                shadowOffsetY={isSelected || isDragging ? 6 : 3}
 199→                preventDefault={preventTouchDefault}
 200→                onClick={canInteract ? onSelect : undefined}
 201→                onTap={canInteract ? onSelect : undefined}
 202→                onDragStart={onDragStart}
 203→                onDragEnd={onDragEnd}
 204→            />
 205→            {isSelected && (
 206→                <Rect
 207→                    x={x}
 208→                    y={y}
 209→                    width={objectWidth}
 210→                    height={objectHeight}
 211→                    stroke="#68d391"
 212→                    strokeWidth={1.7}
 213→                    dash={[6, 4]}
 214→                    rotation={canvasImage?.rotation || 0}
 215→                    listening={false}
 216→                />
 217→            )}
 218→        </>
 219→    );
 220→};
 221→
 222→const CanvasEditor = ({title, onCloseOnSave, addUploadedImagePath, initialCanvasDoc = null, remixSource = null}) => {
 223→    const {session, user} = useAuth();
 224→    const queryClient = useQueryClient();
 225→    const shellRef = useRef(null);
 226→    const ambientLightRef = useRef(null);
 227→    const stageRef = useRef(null);
 228→    const hasHydratedInitialDocRef = useRef(false);
 229→    const snippetInputRef = useRef(null);
 230→    const doodlePointsRef = useRef([]);
 231→    const viewportRef = useRef({scale: 1, x: 0, y: 0});
 232→    const pinchStateRef = useRef({isActive: false, lastDistance: 0, lastCenter: null});
 233→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
 234→
 235→    const [activeTool, setActiveTool] = useState("select");
 236→    const [isSnippetComposerOpen, setIsSnippetComposerOpen] = useState(false);
 237→    const [snippetInput, setSnippetInput] = useState("");
 238→    const [selectedObject, setSelectedObject] = useState(null);
 239→    const [draggingObject, setDraggingObject] = useState(null);
 240→    const [isSending, setIsSending] = useState(false);
 241→    const [isUploadingImage, setIsUploadingImage] = useState(false);
 242→    const [doodleColor, setDoodleColor] = useState(DEFAULT_DOODLE_COLOR);
 243→    const [doodleSize, setDoodleSize] = useState(2.8);
 244→    const [isDrawing, setIsDrawing] = useState(false);
 245→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
 246→    const [canvasMeta, setCanvasMeta] = useState({
 247→        aspectRatio: "1:1",
 248→        gridEnabled: true,
 249→        snapEnabled: true,
 250→        theme: "light"
 251→    });
 252→    const [snippets, setSnippets] = useState([]);
 253→    const [images, setImages] = useState([]);
 254→    const [doodles, setDoodles] = useState([]);
 255→    const [viewport, setViewport] = useState({scale: 1, x: 0, y: 0});
 256→    const [isMobileViewport, setIsMobileViewport] = useState(false);
 257→    const [isMobileDockOpen, setIsMobileDockOpen] = useState(false);
 258→    const [isDoodleDockMinimized, setIsDoodleDockMinimized] = useState(false);
 259→    const [animatingRemovalId, setAnimatingRemovalId] = useState(null);
 260→    const [doodleRedoStack, setDoodleRedoStack] = useState([]);
 261→    const multiTapRef = useRef({fingerCount: 0, timestamp: 0});
 262→    const longPressRef = useRef(null);
 263→    const [pieMenu, setPieMenu] = useState({isOpen: false, position: null, items: []});
 264→
 265→    const updateSnippet = (snippetId, updater) => {
 266→        setSnippets((prev) => prev.map((snippet) => {
 267→            if(snippet.id !== snippetId){
 268→                return snippet;
 269→            }
 270→            const nextValue = typeof updater === "function" ? updater(snippet) : updater;
 271→            return {...snippet, ...nextValue};
 272→        }));
 273→    };
 274→
 275→    const updateImage = (imageId, updater) => {
 276→        setImages((prev) => prev.map((image) => {
 277→            if(image.id !== imageId){
 278→                return image;
 279→            }
 280→            const nextValue = typeof updater === "function" ? updater(image) : updater;
 281→            return {...image, ...nextValue};
 282→        }));
 283→    };
 284→
 285→    useEffect(() => {
 286→        if(hasHydratedInitialDocRef.current || !initialCanvasDoc){
 287→            return;
 288→        }
 289→
 290→        const parsedDoc = parseCanvasDoc(initialCanvasDoc);
 291→        setCanvasMeta((prev) => ({
 292→            ...prev,
 293→            aspectRatio: parsedDoc?.meta?.aspectRatio === "4:5" ? "4:5" : "1:1",
 294→            gridEnabled: Boolean(parsedDoc?.meta?.gridEnabled),
 295→            theme: parsedDoc?.meta?.theme === "dark" ? "dark" : "light"
 296→        }));
 297→        setSnippets((parsedDoc?.snippets || []).map((snippet) => ({
 298→            ...snippet,
 299→            id: snippet.id || createId("snippet"),
 300→            fontStyle: getLegacyFontStyle(snippet.fontStyle),
 301→            zIndex: Number.isFinite(snippet?.zIndex) ? snippet.zIndex : 0
 302→        })));
 303→        setImages((parsedDoc?.images || []).map((image) => ({
 304→            ...image,
 305→            id: image.id || createId("image"),
 306→            zIndex: Number.isFinite(image?.zIndex) ? image.zIndex : 0
 307→        })));
 308→        setDoodles((parsedDoc?.doodles || []).map((doodle) => ({
 309→            ...doodle,
 310→            id: doodle.id || createId("doodle"),
 311→            points: sanitizeNormalizedPoints(doodle.points)
 312→        })));
 313→        hasHydratedInitialDocRef.current = true;
 314→    }, [initialCanvasDoc]);
 315→
 316→    useEffect(() => {
 317→        const getContentWidth = () => {
 318→            const element = shellRef.current;
 319→            if(!element){
 320→                return CANVAS_MAX_WIDTH;
 321→            }
 322→            const computedStyle = getComputedStyle(element);
 323→            const paddingLeft = parseFloat(computedStyle.paddingLeft) || 0;
 324→            const paddingRight = parseFloat(computedStyle.paddingRight) || 0;
 325→            return Math.max(0, element.clientWidth - paddingLeft - paddingRight);
 326→        };
 327→
 328→        const updateShellWidth = () => {
 329→            setShellWidth(getContentWidth());
 330→        };
 331→
 332→        updateShellWidth();
 333→        window.addEventListener("resize", updateShellWidth);
 334→
 335→        let resizeObserver = null;
 336→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 337→            resizeObserver = new ResizeObserver(updateShellWidth);
 338→            resizeObserver.observe(shellRef.current);
 339→        }
 340→
 341→        return () => {
 342→            window.removeEventListener("resize", updateShellWidth);
 343→            if(resizeObserver){
 344→                resizeObserver.disconnect();
 345→            }
 346→        };
 347→    }, []);
 348→
 349→    useEffect(() => {
 350→        const mediaQuery = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT}px)`);
 351→        const syncViewport = () => setIsMobileViewport(mediaQuery.matches);
 352→        syncViewport();
 353→
 354→        if(typeof mediaQuery.addEventListener === "function"){
 355→            mediaQuery.addEventListener("change", syncViewport);
 356→            return () => mediaQuery.removeEventListener("change", syncViewport);
 357→        }
 358→
 359→        mediaQuery.addListener(syncViewport);
 360→        return () => mediaQuery.removeListener(syncViewport);
 361→    }, []);
 362→
 363→    useEffect(() => {
 364→        if(isMobileViewport){
 365→            setIsMobileDockOpen(false);
 366→            return;
 367→        }
 368→        setIsMobileDockOpen(true);
 369→    }, [isMobileViewport]);
 370→
 371→    useEffect(() => {
 372→        if(!isSnippetComposerOpen){
 373→            return;
 374→        }
 375→        const frame = window.requestAnimationFrame(() => snippetInputRef.current?.focus());
 376→        return () => window.cancelAnimationFrame(frame);
 377→    }, [isSnippetComposerOpen]);
 378→
 379→    useEffect(() => {
 380→        if(activeTool !== "doodle"){
 381→            doodlePointsRef.current = [];
 382→            setCurrentDoodlePoints([]);
 383→            setIsDrawing(false);
 384→            setIsDoodleDockMinimized(false);
 385→        }
 386→    }, [activeTool]);
 387→
 388→    const viewportWidth = useMemo(() => Math.max(280, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
 389→    const viewportHeight = getStageHeight(viewportWidth, canvasMeta.aspectRatio);
 390→    const stageWidth = CANVAS_MAX_WIDTH;
 391→    const stageHeight = getStageHeight(stageWidth, canvasMeta.aspectRatio);
 392→    const fitScale = viewportWidth > 0 ? viewportWidth / stageWidth : 1;
 393→    const fitOffsetX = (viewportWidth - stageWidth * fitScale) / 2;
 394→    const fitOffsetY = (viewportHeight - stageHeight * fitScale) / 2;
 395→
 396→    const updateViewport = (updater) => {
 397→        setViewport((prev) => {
 398→            const nextValue = typeof updater === "function" ? updater(prev) : updater;
 399→            const constrained = constrainViewport(nextValue, viewportWidth, viewportHeight);
 400→            viewportRef.current = constrained;
 401→            return constrained;
 402→        });
 403→    };
 404→
 405→    useEffect(() => {
 406→        viewportRef.current = viewport;
 407→    }, [viewport]);
 408→
 409→    useEffect(() => {
 410→        setViewport((prev) => constrainViewport(prev, viewportWidth, viewportHeight));
 411→    }, [viewportWidth, viewportHeight]);
 412→
 413→    useEffect(() => {
 414→        const safePixelRatio = clamp(window.devicePixelRatio || 1, 1, 2.5);
 415→        const stage = stageRef.current;
 416→        if(!stage){
 417→            return;
 418→        }
 419→
 420→        const previousRatio = Konva.pixelRatio;
 421→        Konva.pixelRatio = safePixelRatio;
 422→        stage.getLayers().forEach((layer) => {
 423→            const canvas = layer?.getCanvas?.();
 424→            if(canvas?.setPixelRatio){
 425→                canvas.setPixelRatio(safePixelRatio);
 426→            }
 427→        });
 428→        stage.batchDraw();
 429→        return () => {
 430→            Konva.pixelRatio = previousRatio;
 431→        };
 432→    }, [viewportWidth, viewportHeight]);
 433→
 434→    const getNextZIndex = () => {
 435→        const allZ = [
 436→            ...snippets.map((snippet) => snippet.zIndex || 0),
 437→            ...images.map((image) => image.zIndex || 0)
 438→        ];
 439→        return allZ.length ? Math.max(...allZ) + 1 : 0;
 440→    };
 441→
 442→    const sortedObjects = useMemo(() => {
 443→        const snippetObjects = snippets.map((snippet) => ({kind: "snippet", payload: snippet}));
 444→        const imageObjects = images.map((image) => ({kind: "image", payload: image}));
 445→        return [...snippetObjects, ...imageObjects].sort((a, b) => (a.payload?.zIndex || 0) - (b.payload?.zIndex || 0));
 446→    }, [snippets, images]);
 447→
 448→    const selectedSnippet = selectedObject?.kind === "snippet"
 449→        ? snippets.find((snippet) => snippet.id === selectedObject.id) || null
 450→        : null;
 451→    const canEditObjects = activeTool === "select";
 452→    const isDockVisible = !isMobileViewport || isMobileDockOpen;
 453→    const isDoodleMode = activeTool === "doodle";
 454→    const shouldPreventTouchDefault = isDoodleMode;
 455→    const showMinimizedDoodleDock = isDockVisible && isDoodleMode && isDoodleDockMinimized;
 456→    const hasCanvasContent = snippets.length > 0 || images.length > 0 || doodles.length > 0;
 457→
 458→    const addSnippet = () => {
 459→        const trimmed = snippetInput.trim();
 460→        if(!trimmed){
 461→            return;
 462→        }
 463→
 464→        const jitter = randomPlacement();
 465→        const snippet = {
 466→            id: createId("snippet"),
 467→            text: trimmed,
 468→            x: clamp(0.16 + jitter.xOffset, 0.02, 0.82),
 469→            y: clamp(0.2 + jitter.yOffset, 0.02, 0.82),
 470→            rotation: jitter.rotation,
 471→            fontStyle: "serif",
 472→            scaleX: 1,
 473→            sizeScale: 1,
 474→            zIndex: getNextZIndex()
 475→        };
 476→        setSnippets((prev) => [...prev, snippet]);
 477→        setSelectedObject({kind: "snippet", id: snippet.id});
 478→        setSnippetInput("");
 479→        setIsSnippetComposerOpen(false);
 480→        setActiveTool("select");
 481→    };
 482→
 483→    const addImageFromFile = () => {
 484→        const input = document.createElement("input");
 485→        input.type = "file";
 486→        input.accept = "image/*";
 487→        input.onchange = async(event) => {
 488→            const file = event.target.files?.[0];
 489→            if(!file){
 490→                return;
 491→            }
 492→
 493→            setIsUploadingImage(true);
 494→            try {
 495→                const dimensions = await new Promise((resolve) => {
 496→                    const tempImg = new window.Image();
 497→                    const objectUrl = URL.createObjectURL(file);
 498→                    tempImg.onload = () => {
 499→                        resolve({
 500→                            width: tempImg.naturalWidth || 1200,
 501→                            height: tempImg.naturalHeight || 800
 502→                        });
 503→                        URL.revokeObjectURL(objectUrl);
 504→                    };
 505→                    tempImg.onerror = () => {
 506→                        resolve({width: 1200, height: 800});
 507→                        URL.revokeObjectURL(objectUrl);
 508→                    };
 509→                    tempImg.src = objectUrl;
 510→                });
 511→
 512→                const formdata = new FormData();
 513→                formdata.append("image", file);
 514→                const uploaded = await saveJournalImage(session?.access_token, formdata);
 515→                const imageSrc = uploaded?.img_url;
 516→                if(!imageSrc){
 517→                    return;
 518→                }
 519→
 520→                const filePath = imageSrc.split("/journal-images/").pop();
 521→                if(filePath && addUploadedImagePath){
 522→                    addUploadedImagePath(filePath);
 523→                }
 524→
 525→                const ratio = dimensions.width / dimensions.height;
 526→                const baseWidth = 0.34;
 527→                const rawHeight = ratio > 0 ? baseWidth / ratio : 0.24;
 528→                const imgJitter = randomPlacement();
 529→                const imageObject = {
 530→                    id: createId("image"),
 531→                    src: imageSrc,
 532→                    x: clamp(0.18 + imgJitter.xOffset, 0.02, 0.82),
 533→                    y: clamp(0.24 + imgJitter.yOffset, 0.02, 0.82),
 534→                    width: clamp(baseWidth, 0.14, 0.8),
 535→                    height: clamp(rawHeight, 0.12, 0.8),
 536→                    rotation: imgJitter.rotation,
 537→                    scaleX: 1,
 538→                    zIndex: getNextZIndex()
 539→                };
 540→                setImages((prev) => [...prev, imageObject]);
 541→                setSelectedObject({kind: "image", id: imageObject.id});
 542→                setActiveTool("select");
 543→            } catch (error) {
 544→                console.error("Canvas image upload failed:", error);
 545→            } finally {
 546→                setIsUploadingImage(false);
 547→            }
 548→        };
 549→
 550→        input.click();
 551→    };
 552→
 553→    const bringToFront = () => {
 554→        if(!selectedObject){
 555→            return;
 556→        }
 557→        const nextZ = getNextZIndex();
 558→        if(selectedObject.kind === "snippet"){
 559→            updateSnippet(selectedObject.id, {zIndex: nextZ});
 560→        } else {
 561→            updateImage(selectedObject.id, {zIndex: nextZ});
 562→        }
 563→    };
 564→
 565→    const sendToBack = () => {
 566→        if(!selectedObject){
 567→            return;
 568→        }
 569→        const allZ = [
 570→            ...snippets.map((snippet) => snippet.zIndex || 0),
 571→            ...images.map((image) => image.zIndex || 0)
 572→        ];
 573→        const minZ = allZ.length ? Math.min(...allZ) - 1 : -1;
