1714→                                className={`${styles.secondaryButton} ${canvasMeta.theme === "dark" ? styles.toolButtonActive : ""}`}
1715→                                onClick={() => setCanvasMeta((prev) => ({...prev, theme: prev.theme === "dark" ? "light" : "dark"}))}
1716→                            >
