 21→/* ── Overlay backdrop ── */
 22→.editor-parent-container {
 23→    display: flex;
 24→    justify-content: center;
 25→    align-items: center;
 26→    position: absolute;
 27→    width: 100%;
 28→    height: 100%;
 29→    background-color: var(--bg-overlay);
 30→    backdrop-filter: blur(25px);
 31→    z-index: 130;
 32→}
