 34→/* ── Main editor card ── */
 35→.editor-container {
 36→    display: flex;
 37→    flex-direction: column;
 38→    width: 100%;
 39→    max-width: 720px;
 40→    height: 80%;
 41→    min-height: 0;
 42→    overflow: hidden;
 43→    background-color: var(--editor-bg);
 44→    color: var(--editor-text);
 45→    border-radius: 16px;
 46→    padding: 1rem 1.5rem;
 47→    box-shadow: var(--shadow-modal);
 48→}
